import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/location/model/geofence.dart'; void main() { group('Geofence', () { final geofence = Geofence(geofenceId: 'g1', label: 'Home', latitude: 6.5244, longitude: 3.3792, radiusMeters: 100); test('point inside geofence', () { expect(geofence.containsPoint(6.5244, 3.3792), true); }); test('distant point outside geofence', () { expect(geofence.containsPoint(48.8566, 2.3522), false); }); }); }